/**
 * Bounded exact surface estimator for a finite relation followed by statement-pattern lookups.
 *
 * <p>
 * This is deliberately a factor-cost primitive rather than a join planner. It resolves the finite prefix through the
 * store just far enough to price the next physical lookup in the same total-for-context units used by Cascades.
 */
final class LmdbFiniteJoinSurfaceEstimator {

	private static final int MAX_FACTORS = 8;
	private static final int MAX_ROWS = 16_384;
	private static final int MAX_SCANNED_ROWS = 4_096;
	private static final long UNBOUND_ID = Long.MIN_VALUE;

	private final ValueStore valueStore;
	private final TripleStore tripleStore;

	LmdbFiniteJoinSurfaceEstimator(ValueStore valueStore, TripleStore tripleStore) {
		this.valueStore = valueStore;
		this.tripleStore = tripleStore;
	}

	Optional<SurfaceEstimate> estimate(List<TupleExpr> prefixFactors, TupleExpr factor,
			Map<String, Set<Value>> finiteBindingValues) {
		List<TupleExpr> effectivePrefix = prefixFactors == null ? List.of() : prefixFactors;
		if (valueStore == null || tripleStore == null || factor == null
				|| effectivePrefix.size() + 1 > MAX_FACTORS) {
			return Optional.empty();
		}
		List<BindingSetAssignment> assignments = new ArrayList<>();
		List<StatementPattern> prefixPatterns = new ArrayList<>();
		for (TupleExpr prefixFactor : effectivePrefix) {
			if (prefixFactor instanceof BindingSetAssignment assignment) {
				assignments.add(assignment);
			} else if (prefixFactor instanceof StatementPattern pattern) {
				prefixPatterns.add(pattern);
			} else {
				return Optional.empty();
			}
		}
		if (!(factor instanceof StatementPattern surfacePattern)
				|| (assignments.isEmpty() && !hasSingleFiniteDomain(finiteBindingValues))) {
			return Optional.empty();
		}

		VarSlots slots = buildVarSlots(assignments, prefixPatterns, surfacePattern, finiteBindingValues);
		List<long[]> rows;
		try {
			rows = initialRows(assignments, finiteBindingValues, slots);
		} catch (IOException | RuntimeException e) {
			return Optional.empty();
		}
		if (rows == null) {
			return Optional.empty();
		}
		if (rows.isEmpty()) {
			return Optional.of(new SurfaceEstimate(0.0d, 0.0d, 0L, 0,
					FiniteRelationEstimate.fromRows(slots.names(), List.of(),
							"lmdb-finite-derived-surface"),
					true, 0));
		}

		long scannedRows = 0L;
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			for (StatementPattern pattern : prefixPatterns) {
				if (!connectsToBoundRow(pattern, rows, slots)) {
					return Optional.empty();
				}
				Expansion expansion = expand(txn, rows, slots, pattern, scannedRows);
				if (expansion == null) {
					return Optional.empty();
				}
				rows = expansion.rows();
				scannedRows = expansion.scannedRows();
				if (rows.isEmpty()) {
					return Optional.of(new SurfaceEstimate(0.0d, 0.0d, scannedRows, 0,
							finiteRelation(slots, rows), true, 0));
				}
			}
			double prefixRows = rows.size();
			if (!connectsToBoundRow(surfacePattern, rows, slots)) {
				return Optional.empty();
			}
			SurfaceCardinality cardinality = surfaceCardinality(rows, slots, surfacePattern);
			if (cardinality.available()
					&& cardinality.rows() > Math.min(MAX_ROWS, MAX_SCANNED_ROWS)) {
				return Optional.of(new SurfaceEstimate(cardinality.rows(), prefixRows, scannedRows,
						rows.size(), null, false, cardinality.probes()));
			}
			Expansion surface = expand(txn, rows, slots, surfacePattern, scannedRows);
			if (surface == null) {
				return cardinality.available() && cardinality.rows() > 0.0d
						? Optional.of(new SurfaceEstimate(cardinality.rows(), prefixRows, scannedRows,
								rows.size(), null, false, cardinality.probes()))
						: Optional.empty();
			}
			return Optional.of(new SurfaceEstimate(surface.rows().size(), prefixRows,
					surface.scannedRows(), rows.size(), finiteRelation(slots, surface.rows()), true,
					cardinality.probes()));
		} catch (IOException | RuntimeException e) {
			return Optional.empty();
		}
	}

	private SurfaceCardinality surfaceCardinality(List<long[]> input, VarSlots slots,
			StatementPattern pattern) throws IOException {
		double rows = 0.0d;
		int probes = 0;
		for (long[] row : input) {
			PatternIds ids = patternIds(pattern, row, slots);
			if (ids == null || requiresUnboundRepeatedVariable(pattern, row, slots)) {
				return SurfaceCardinality.unavailable();
			}
			if (ids.zeroRows()) {
				continue;
			}
			double estimate = tripleStore.planningCardinality(ids.subjectId(), ids.predicateId(),
					ids.objectId(), ids.contextId());
			if (!Double.isFinite(estimate) || estimate < 0.0d) {
				return SurfaceCardinality.unavailable();
			}
			rows = saturatingAdd(rows, estimate);
			probes++;
		}
		return new SurfaceCardinality(true, rows, probes);
	}

	private static boolean requiresUnboundRepeatedVariable(StatementPattern pattern, long[] row, VarSlots slots) {
		List<Var> variables = pattern.getVarList();
		for (int left = 0; left < variables.size(); left++) {
			Var leftVariable = variables.get(left);
			if (leftVariable == null || leftVariable.hasValue()) {
				continue;
			}
			for (int right = left + 1; right < variables.size(); right++) {
				Var rightVariable = variables.get(right);
				if (rightVariable != null && !rightVariable.hasValue()
						&& leftVariable.getName().equals(rightVariable.getName())) {
					int slot = slots.index(leftVariable.getName());
					if (slot < 0 || row[slot] == UNBOUND_ID) {
						return true;
					}
				}
			}
		}
		return false;
	}

	private static double saturatingAdd(double left, double right) {
		if (left >= Double.MAX_VALUE - right) {
			return Double.MAX_VALUE;
		}
		return left + right;
	}

	private List<long[]> initialRows(List<BindingSetAssignment> assignments,
			Map<String, Set<Value>> finiteBindingValues, VarSlots slots) throws IOException {
		List<long[]> rows = new ArrayList<>();
		rows.add(emptyRow(slots.size()));
		if (!assignments.isEmpty()) {
			for (BindingSetAssignment assignment : assignments) {
				List<long[]> joined = new ArrayList<>();
				for (long[] row : rows) {
					for (BindingSet bindingSet : assignment.getBindingSets()) {
						long[] merged = merge(row, slots, bindingSet);
						if (merged != null) {
							joined.add(merged);
							if (joined.size() > MAX_ROWS) {
								return null;
							}
						}
					}
				}
				rows = joined;
				if (rows.isEmpty()) {
					return rows;
				}
			}
			return rows;
		}

		Map.Entry<String, Set<Value>> finite = finiteBindingValues.entrySet().iterator().next();
		List<long[]> finiteRows = new ArrayList<>(finite.getValue().size());
		int slot = slots.index(finite.getKey());
		for (Value value : finite.getValue()) {
			long id = storedId(value);
			if (id == UNBOUND_ID) {
				continue;
			}
			long[] row = emptyRow(slots.size());
			row[slot] = id;
			finiteRows.add(row);
		}
		return finiteRows;
	}

	private Expansion expand(Txn txn, List<long[]> input, VarSlots slots, StatementPattern pattern,
			long alreadyScanned) throws IOException {
		List<long[]> output = new ArrayList<>();
		long scanned = alreadyScanned;
		for (long[] row : input) {
			PatternIds ids = patternIds(pattern, row, slots);
			if (ids == null) {
				return null;
			}
			if (ids.zeroRows()) {
				continue;
			}
			try (RecordIterator records = tripleStore.getTriples(txn, ids.subjectId(), ids.predicateId(),
					ids.objectId(), ids.contextId(), true)) {
				long[] quad;
				while ((quad = records.next()) != null) {
					if (++scanned > MAX_SCANNED_ROWS) {
						return null;
					}
					long[] merged = merge(row, slots, pattern, quad);
					if (merged != null) {
						output.add(merged);
						if (output.size() > MAX_ROWS) {
							return null;
						}
					}
				}
			}
		}
		return new Expansion(output, scanned);
	}

	private PatternIds patternIds(StatementPattern pattern, long[] row, VarSlots slots) throws IOException {
		long subject = componentId(pattern.getSubjectVar(), Component.SUBJECT, row, slots);
		long predicate = componentId(pattern.getPredicateVar(), Component.PREDICATE, row, slots);
		long object = componentId(pattern.getObjectVar(), Component.OBJECT, row, slots);
		long context = componentId(pattern.getContextVar(), Component.CONTEXT, row, slots);
		return subject == UNBOUND_ID || predicate == UNBOUND_ID || object == UNBOUND_ID || context == UNBOUND_ID
				? PatternIds.zero()
				: new PatternIds(subject, predicate, object, context, false);
	}

	private long componentId(Var variable, Component component, long[] row, VarSlots slots) throws IOException {
		if (variable == null) {
			return LmdbValue.UNKNOWN_ID;
		}
		if (!variable.hasValue()) {
			int slot = slots.index(variable.getName());
			return slot < 0 || row[slot] == UNBOUND_ID ? LmdbValue.UNKNOWN_ID : row[slot];
		}
		Value value = variable.getValue();
		if (!compatible(component, value)) {
			return UNBOUND_ID;
		}
		return storedId(value);
	}

	private long[] merge(long[] row, VarSlots slots, BindingSet bindingSet) throws IOException {
		long[] merged = row;
		for (String bindingName : bindingSet.getBindingNames()) {
			Value value = bindingSet.getValue(bindingName);
			if (value == null) {
				continue;
			}
			long id = storedId(value);
			if (id == UNBOUND_ID) {
				return null;
			}
			merged = addBinding(merged, row, slots, bindingName, id);
			if (merged == null) {
				return null;
			}
		}
		return merged;
	}

	private static long[] merge(long[] row, VarSlots slots, StatementPattern pattern, long[] quad) {
		long[] merged = addBinding(row, row, slots, pattern.getSubjectVar(), quad[TripleStore.SUBJ_IDX]);
		merged = merged == null ? null
				: addBinding(merged, row, slots, pattern.getPredicateVar(), quad[TripleStore.PRED_IDX]);
		merged = merged == null ? null
				: addBinding(merged, row, slots, pattern.getObjectVar(), quad[TripleStore.OBJ_IDX]);
		return merged == null ? null
				: addBinding(merged, row, slots, pattern.getContextVar(), quad[TripleStore.CONTEXT_IDX]);
	}

	private static long[] addBinding(long[] current, long[] original, VarSlots slots, Var variable, long id) {
		return variable == null || variable.hasValue()
				? current
				: addBinding(current, original, slots, variable.getName(), id);
	}

	private static long[] addBinding(long[] current, long[] original, VarSlots slots, String name, long id) {
		int slot = slots.index(name);
		if (slot < 0) {
			return current;
		}
		long existing = current[slot];
		if (existing != UNBOUND_ID) {
			return existing == id ? current : null;
		}
		if (current == original) {
			current = Arrays.copyOf(original, original.length);
		}
		current[slot] = id;
		return current;
	}

	private long storedId(Value value) throws IOException {
		if (value == null) {
			return UNBOUND_ID;
		}
		long id = valueStore.getId(value);
		return id == LmdbValue.UNKNOWN_ID ? UNBOUND_ID : id;
	}

	private FiniteRelationEstimate finiteRelation(VarSlots slots, List<long[]> idRows) throws IOException {
		List<List<Value>> rows = new ArrayList<>(idRows.size());
		for (long[] idRow : idRows) {
			List<Value> row = new ArrayList<>(idRow.length);
			for (long id : idRow) {
				row.add(id == UNBOUND_ID ? null : valueStore.getValue(id));
			}
			rows.add(row);
		}
		return FiniteRelationEstimate.fromRows(slots.names(), rows, "lmdb-finite-derived-surface");
	}

	private static boolean connectsToBoundRow(StatementPattern pattern, List<long[]> rows, VarSlots slots) {
		for (Var variable : pattern.getVarList()) {
			if (variable == null || variable.hasValue()) {
				continue;
			}
			int slot = slots.index(variable.getName());
			if (slot < 0) {
				continue;
			}
			for (long[] row : rows) {
				if (row[slot] != UNBOUND_ID) {
					return true;
				}
			}
		}
		return false;
	}

	private static boolean compatible(Component component, Value value) {
		return switch (component) {
		case SUBJECT, CONTEXT -> value instanceof Resource;
		case PREDICATE -> value instanceof IRI;
		case OBJECT -> value != null;
		};
	}

	private static boolean hasSingleFiniteDomain(Map<String, Set<Value>> finiteBindingValues) {
		return finiteBindingValues != null && finiteBindingValues.size() == 1
				&& finiteBindingValues.values().iterator().next() != null
				&& !finiteBindingValues.values().iterator().next().isEmpty();
	}

	private static VarSlots buildVarSlots(List<BindingSetAssignment> assignments,
			List<StatementPattern> prefixPatterns, StatementPattern surfacePattern,
			Map<String, Set<Value>> finiteBindingValues) {
		VarSlots slots = new VarSlots();
		for (BindingSetAssignment assignment : assignments) {
			assignment.getBindingNames().forEach(slots::add);
		}
		if (finiteBindingValues != null) {
			finiteBindingValues.keySet().forEach(slots::add);
		}
		for (StatementPattern pattern : prefixPatterns) {
			addPatternVariables(slots, pattern);
		}
		addPatternVariables(slots, surfacePattern);
		return slots;
	}

	private static void addPatternVariables(VarSlots slots, StatementPattern pattern) {
		for (Var variable : pattern.getVarList()) {
			if (variable != null && !variable.hasValue()) {
				slots.add(variable.getName());
			}
		}
	}

	private static long[] emptyRow(int size) {
		long[] row = new long[size];
		Arrays.fill(row, UNBOUND_ID);
		return row;
	}

	record SurfaceEstimate(double surfaceRows, double prefixRows, long scannedRows, int branchCount,
			FiniteRelationEstimate relation, boolean exact, int cardinalityProbes) {
	}

	private record SurfaceCardinality(boolean available, double rows, int probes) {
		private static SurfaceCardinality unavailable() {
			return new SurfaceCardinality(false, Double.NaN, 0);
		}
	}

	private record Expansion(List<long[]> rows, long scannedRows) {
	}

	private record PatternIds(long subjectId, long predicateId, long objectId, long contextId, boolean zeroRows) {
		private static PatternIds zero() {
			return new PatternIds(0L, 0L, 0L, 0L, true);
		}
	}

	private enum Component {
		SUBJECT,
		PREDICATE,
		OBJECT,
		CONTEXT
	}

	private static final class VarSlots {
		private final Map<String, Integer> indexes = new HashMap<>();
		private final List<String> names = new ArrayList<>();

		void add(String name) {
			if (name != null && !indexes.containsKey(name)) {
				indexes.put(name, names.size());
				names.add(name);
			}
		}

		int index(String name) {
			Integer index = indexes.get(name);
			return index == null ? -1 : index;
		}

		int size() {
			return names.size();
		}

		List<String> names() {
			return names;
		}
	}
}
